INSERT INTO public.courses (id, instructor_id, title, description, category, tags, price, total_hours, status, sort_order) VALUES
('c0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', '入門班：智働話啟航', '從零開始理解 AI 與人機協作的核心思維，掌握參數、變數、亂數的概念架構', 'quest', ARRAY['AI', '智働話', '入門'], 0, 8, 'published', 1),
('c0000000-0000-0000-0000-000000000002', 'b0000000-0000-0000-0000-000000000001', '基礎班：Vibe Coding 實作', '用對話方式打造完整的前端介面原型', 'basic', ARRAY['Vibe Coding', 'Lovable', '前端'], 5000, 16, 'published', 2),
('c0000000-0000-0000-0000-000000000003', 'b0000000-0000-0000-0000-000000000001', '中階班：工作流程自動化', '使用 Make.com / n8n 建立完整的 Workflow 自動化流程', 'intermediate', ARRAY['Make.com', 'n8n', '自動化'], 8000, 24, 'published', 3),
('c0000000-0000-0000-0000-000000000004', 'b0000000-0000-0000-0000-000000000001', '高階班：AI Agent 部署', '建構智慧客服與任務代理，打造 24 小時數位管家', 'advanced', ARRAY['AI Agent', 'Dify', 'RAG'], 12000, 32, 'published', 4),
('c0000000-0000-0000-0000-000000000005', 'b0000000-0000-0000-0000-000000000001', 'Postly 社群自動化特訓', '社群媒體自動排程與內容管理實戰', 'special', ARRAY['Postly', '社群', '自動化'], 3000, 8, 'draft', 5),
('c0000000-0000-0000-0000-000000000006', 'b0000000-0000-0000-0000-000000000001', 'Lovable 進階開發', '深入 Lovable 平台的進階功能與 Supabase 整合', 'special', ARRAY['Lovable', 'Supabase', '全端'], 6000, 16, 'draft', 6),
('c0000000-0000-0000-0000-000000000007', 'b0000000-0000-0000-0000-000000000001', '個人 AI 助理打造', '從零打造個人專屬的 AI 助理系統', 'special', ARRAY['AI', '個人助理', 'GPT'], 5000, 12, 'draft', 7)
