INSERT INTO public.unit_sections (unit_id, type, content_json, sort_order) VALUES
('d0000000-0000-0000-0000-000000000001', 'highlight', '{"title":"📌 學期的概念起手式","body":"在決策的流動中，控制可控的，識別未知的，接納不確定的——這是人機協作的智慧。","link_url":"https://dao.smart4a.tw/","link_text":"🔗 深入了解「道」的概念 →"}', 1),
('d0000000-0000-0000-0000-000000000001', 'card_grid', '{"title":"參數・變數・亂數","cards":[{"icon":"●","title":"參數","desc":"可重複的秩序","note":"開發工作流程"},{"icon":"◐","title":"變數","desc":"待識別的契機","note":"設計思維模式"},{"icon":"○","title":"亂數","desc":"亂中求有序","note":"規劃運作法則"}]}', 2),
('d0000000-0000-0000-0000-000000000001', 'highlight', '{"title":"☯︎ 函數 — 全方位整合","body":"整合參數・變數・亂數"}', 3),
('d0000000-0000-0000-0000-000000000001', 'bordered_list', '{"title":"函數的四大特性","items":[{"title":"整合性","desc":"函數整合了參數、變數、亂數這三個元素","color":"primary"},{"title":"轉換性","desc":"太極的陰陽轉換，就像函數的「輸入→處理→輸出」","color":"primary"},{"title":"完整性","desc":"函數是一個完整的運算單元，包含所有必要元素","color":"accent"},{"title":"動態平衡","desc":"太極講究平衡，函數也在不同元素間取得運算平衡","color":"accent"}]}', 4),
('d0000000-0000-0000-0000-000000000001', 'text', '{"title":"AI 時代的工作流程革命","subtitle":"從自動化走向智働話"}', 5),
('d0000000-0000-0000-0000-000000000001', 'card_grid', '{"cards":[{"icon":"●","title":"參數 Parameters","desc":"可量化、可精確定義\n例如：價格 < 2000萬、3房2廳、40坪以內","note":"傳統流程自動化 Flow"},{"icon":"◐","title":"變數 Variables","desc":"需要理解與判斷\n例如：附近好停車、採光通風好、5年內會增值","note":"AI Agent 智能判斷"},{"icon":"○","title":"亂數 Random","desc":"不可預測、高度動態\n例如：突發政策變動、個人直覺偏好、市場突發事件","note":"決策判斷、人機協作"}]}', 6),
('d0000000-0000-0000-0000-000000000001', 'text', '{"title":"系統思維的相通性"}', 7),
('d0000000-0000-0000-0000-000000000001', 'list', '{"title":"易經的核心：變易、不易、簡易","items":["變易：數據會變、模式會演化，就像卦象的變化","不易：底層邏輯規律不變，就像 AI 的數學基礎","簡易：複雜系統用簡單規則運作，就像神經網路的基本原理"]}', 8),
('d0000000-0000-0000-0000-000000000001', 'text', '{"title":"道德經的「無為而治」","body":"老子說「道生一，一生二，二生三，三生萬物」，這不就是深度學習的層層抽象嗎？最底層的簡單規則，透過層層堆疊，產生複雜智能。\n\n而「無為而治」更像是讓 AI 自己學習，不要過度干預（overfitting）。"}', 9),
('d0000000-0000-0000-0000-000000000001', 'flow', '{"title":"易經與道德經的 AI 詮釋架構","steps":[{"label":"道（本質層）","sub":"理解 AI 是什麼"},{"label":"易（應用層）","sub":"知道何時如何用"},{"label":"智働話（實踐層）","sub":"人機協同創造價值"}]}', 10),
('d0000000-0000-0000-0000-000000000001', 'highlight', '{"title":"☯︎ 智働話的真諦","body":"不是人控制 AI，也不是 AI 取代人，而是兩者協同產生更大的價值。\n\n這種東方哲學思維，反而讓你在教「Vibe Coding」時，能跳脫純技術的框架，講出更深層的道理。"}', 11);
INSERT INTO public.unit_sections (unit_id, type, content_json, sort_order) VALUES
('d0000000-0000-0000-0000-000000000002', 'text', '{"title":"一日洞見，終身受用","body":"我們以一日之課，為你開啟智働話的八個核心覺察："}', 1),
('d0000000-0000-0000-0000-000000000002', 'bordered_list', '{"title":"【前置思維】","items":[{"title":"✦ 應用之道｜何處用 AI？","desc":"辨識工作中 AI 可介入的場景與時機","color":"primary"},{"title":"✦ 選擇之智｜何時用 AI？","desc":"判斷任務性質，決定 AI 協作的必要性","color":"primary"},{"title":"✦ 層次之辨｜自動化 vs 智働話？","desc":"洞察兩者本質差異，選擇適切的協作模式","color":"primary"}]}', 2),
('d0000000-0000-0000-0000-000000000002', 'bordered_list', '{"title":"【協作能力】","items":[{"title":"✦ 整合之藝｜如何與 AI 共事？","desc":"讓你的工作流程與 AI 能力無縫融合","color":"accent"},{"title":"✦ 規劃之術｜如何構思所需？","desc":"從模糊想法到清晰藍圖的思維路徑","color":"accent"},{"title":"✦ 提問之功｜如何問對問題？","desc":"掌握精準提問的技巧，讓 AI 理解你的真實需求","color":"accent"}]}', 3),
('d0000000-0000-0000-0000-000000000002', 'bordered_list', '{"title":"【實踐技能】","items":[{"title":"✦ 流程之解｜逆向工程拆解術","desc":"從終點反推起點，洞察流程背後的設計邏輯","color":"primary"},{"title":"✦ 創造之實｜Vibe Coding 建構法","desc":"用直覺式編碼方式，將想法快速轉化為可用原型","color":"primary"}]}', 4),
('d0000000-0000-0000-0000-000000000002', 'highlight', '{"title":"智働話","body":"從「流程自動化」到「協作智働話」\n不只是機械執行，而是智慧賦能、人機共舞、對話驅動的全新範式"}', 5),
('d0000000-0000-0000-0000-000000000002', 'card_grid', '{"title":"三大核心支柱","cards":[{"icon":"智","title":"AI 智能賦能","desc":"不只是機械執行，而是具備學習、判斷與優化能力","note":"深度學習 · 智慧決策 · 持續優化"},{"icon":"働","title":"人機協同共創","desc":"非取代人力，而是人的創意 + 機器的效率，1+1>2","note":"無縫協作 · 創意結合 · 綜效最大化"},{"icon":"話","title":"自然語言互動","desc":"透過對話式介面，讓溝通變得直覺、門檻降低","note":"自然對話 · 直覺操作 · 低門檻"}]}', 6);
INSERT INTO public.unit_sections (unit_id, type, content_json, sort_order) VALUES
('d0000000-0000-0000-0000-000000000003', 'highlight', '{"title":"📌 本單元課程重點指南","body":"• 掌握三段式學習框架\n• 理解逆向工程思維\n• 從思考到行動的轉化"}', 1),
('d0000000-0000-0000-0000-000000000003', 'text', '{"title":"三段式學習旅程","body":"從思維到行動的實踐之路"}', 2),
('d0000000-0000-0000-0000-000000000003', 'bordered_list', '{"title":"第一段｜逆向工程：從結果看本質","items":[{"title":"拆解工作流程","desc":"從表面的操作步驟，深入到背後的思考邏輯","color":"accent"},{"title":"洞察思維流程","desc":"理解一個流程為何如此設計","color":"accent"},{"title":"反推互動流程","desc":"轉化為與 AI 的對話設計","color":"accent"}]}', 3),
('d0000000-0000-0000-0000-000000000003', 'bordered_list', '{"title":"第二段｜Vibe Coding：親手打造工具","items":[{"title":"規劃","desc":"清楚表達你的需求和想像","color":"primary"},{"title":"設計","desc":"用對話方式讓 AI 設計介面","color":"primary"},{"title":"打磨","desc":"從粗糙到精緻，每次對話都讓原型更接近理想","color":"primary"}]}', 4),
('d0000000-0000-0000-0000-000000000003', 'bordered_list', '{"title":"第三段｜三元整合：掌握 AI 決策核心","items":[{"title":"亂數｜掌握決策介面的靈活性","desc":"在需要創意和多樣性時，讓 AI 展現靈活的一面","color":"accent"},{"title":"參數｜控制流程的精確度","desc":"設定明確的規則和條件，讓 AI 精準執行","color":"primary"},{"title":"變數｜識別情境的動態性","desc":"捕捉環境的變化，讓 AI 根據情境做出調整","color":"primary"}]}', 5);
INSERT INTO public.unit_sections (unit_id, type, content_json, sort_order) VALUES
('d0000000-0000-0000-0000-000000000004', 'text', '{"title":"深入理解學習的三個階段","body":"將學習過程拆解為可執行的階段，循序漸進掌握智働話。"}', 1),
('d0000000-0000-0000-0000-000000000004', 'card_grid', '{"cards":[{"icon":"🏠","title":"蓋房子","desc":"打造完整原型\nVibe Coding\n用對話方式讓 AI 設計網頁介面","note":"規劃使用者旅程與操作動線"},{"icon":"⚡","title":"水電裝潢","desc":"建置工作流程\nMake.com / n8n\n將前台、後台、金流、通知串接整合","note":"實現全自動化運作"},{"icon":"🛡️","title":"保全家管","desc":"部署 AI Agent\nDify\n建構智慧客服與任務代理","note":"24 小時線上即時回應"}]}', 2);
INSERT INTO public.unit_sections (unit_id, type, content_json, sort_order) VALUES
('d0000000-0000-0000-0000-000000000005', 'highlight', '{"title":"📌 本單元課程重點指南","body":"• 學會正確的提示詞撰寫方式\n• 掌握 Lovable 的核心工作流程\n• 理解設計風格的重要性"}', 1),
('d0000000-0000-0000-0000-000000000005', 'text', '{"title":"一、為什麼提示詞（Prompt）很重要？","body":"提示詞就是你跟 AI 溝通的語言。寫得好，AI 就能精準理解你的意圖，一次做對；寫不好，就像跟一個聽不懂你說話的人合作，反覆修改浪費時間。"}', 2),
('d0000000-0000-0000-0000-000000000005', 'list', '{"title":"二、一開始就講清楚","items":["目的：你要做什麼？","對象：誰會用？","範圍：做到什麼程度？","風格：要什麼感覺？"]}', 3),
('d0000000-0000-0000-0000-000000000005', 'text', '{"title":"三、設計風格一開始就要定好","body":"設計風格是地基，不是最後加的裝飾。Lovable 要早早就知道你想要什麼感覺。不然做出來的東西功能可能沒問題，但看起來就是怪怪的。"}', 4),
('d0000000-0000-0000-0000-000000000005', 'highlight', '{"title":"🎯 進階技巧：讓 Lovable 主動問你問題","body":"想要 Lovable 做出更符合你期待的東西？有個超好用的技巧：先講你要什麼功能，然後在提示詞最後加上：\n\n「如果有任何不清楚的地方，請問我問題，讓你可以完全理解我想要什麼。」"}', 5);
INSERT INTO public.unit_sections (unit_id, type, content_json, sort_order) VALUES
('d0000000-0000-0000-0000-000000000006', 'highlight', '{"title":"📌 本單元課程重點指南","body":"• 理解前端、中端、後端的角色分工\n• 掌握三層架構如何協同運作\n• 學會用建築比喻理解系統架構"}', 1),
('d0000000-0000-0000-0000-000000000006', 'card_grid', '{"cards":[{"icon":"🎨","title":"前端 Frontend","desc":"使用者看到的一切\n網頁介面、按鈕、表單、動畫","note":"比喻：房子的外觀裝潢"},{"icon":"⚙️","title":"中端 Middleware","desc":"流程的調度中心\nAPI 串接、工作流程自動化、邏輯判斷","note":"比喻：房子的水電管線"},{"icon":"🗄️","title":"後端 Backend","desc":"資料的儲存與運算\n資料庫管理、使用者驗證、安全性","note":"比喻：房子的地基結構"}]}', 2),
('d0000000-0000-0000-0000-000000000006', 'flow', '{"title":"🔄 三層協作流程","steps":[{"label":"使用者點擊按鈕"},{"label":"中端處理請求"},{"label":"後端查詢資料"},{"label":"前端顯示結果"}]}', 3),
('d0000000-0000-0000-0000-000000000006', 'highlight', '{"title":"💡 入門班專注於「前端」設計","body":"在這個階段，你主要學習用對話方式設計介面。中端與後端的整合會在基礎班與中階班深入探討。"}', 4);
INSERT INTO public.unit_sections (unit_id, type, content_json, sort_order) VALUES
('d0000000-0000-0000-0000-000000000007', 'highlight', '{"title":"🔌 介面與管線的關係","body":"想像你的系統是一棟房子，介面就是你看到的開關與出水口，而管線就是牆壁裡看不見的水電配線。"}', 1),
('d0000000-0000-0000-0000-000000000007', 'card_grid', '{"cards":[{"icon":"🔘","title":"介面的按鈕 = 開關","desc":"觸發管線運作的入口","note":"Input"},{"icon":"📊","title":"介面的表格 = 出口","desc":"管線運作結果的呈現","note":"Output"}]}', 2),
('d0000000-0000-0000-0000-000000000007', 'text', '{"title":"🔘 觸發開關：按鈕如何啟動管線","body":"當用戶點擊一個按鈕時，就像按下電燈開關——電流開始在管線中流動，最終點亮燈泡。"}', 3),
('d0000000-0000-0000-0000-000000000007', 'list', '{"title":"✅ 必須保留的管線","items":["核心功能觸發管線：訂購、登入、付款按鈕","關鍵資料展示管線：訂單列表、會員資料、庫存狀態","即時同步管線：確保前後台資料一致"]}', 4),
('d0000000-0000-0000-0000-000000000007', 'list', '{"title":"⚠️ 可暫時移除的管線","items":["進階分析管線：複雜的數據分析與預測","社群整合管線：第三方社群平台連接","自動化通知管線：非核心的通知推送"]}', 5);
INSERT INTO public.unit_sections (unit_id, type, content_json, sort_order) VALUES
('d0000000-0000-0000-0000-000000000008', 'text', '{"title":"從樣品屋到成品屋","body":"Vibe Coding 做出的是樣品屋（Prototype），要轉化為成品屋需要考量維護、擴充、安全等面向。"}', 1),
('d0000000-0000-0000-0000-000000000008', 'card_grid', '{"cards":[{"icon":"🏗️","title":"樣品屋思維","desc":"「我能做出來就好」\n快速驗證想法","note":"Prototype"},{"icon":"🏠","title":"成品屋思維","desc":"「別人能接手維護」\n可擴展、可維護","note":"Production"}]}', 2),
('d0000000-0000-0000-0000-000000000008', 'highlight', '{"title":"🔗 為什麼中間層如此重要？","body":"如果把所有東西都放在前端，未來會面臨巨大的維護問題。中間層的存在，是為了：多人協作、權限控管、流程可視化。"}', 3),
('d0000000-0000-0000-0000-000000000008', 'list', '{"title":"📋 成品屋五大維護面向","items":["維護人員：角色分工、備援機制","規格描述：API 文件、流程圖、商業規則","流程變更：變更申請、影響評估、測試驗證","維護權限：讀取/修改/部署/緊急權限","知識傳承：操作手冊、故障排除、設計決策"],"ordered":true}', 4);
INSERT INTO public.unit_sections (unit_id, type, content_json, sort_order) VALUES
('d0000000-0000-0000-0000-000000000009', 'highlight', '{"title":"📌 本單元課程重點指南","body":"• 建立系統化的驗收檢核清單\n• 學會不同層面的測試方法\n• 掌握問題回報與追蹤流程"}', 1),
('d0000000-0000-0000-0000-000000000009', 'card_grid', '{"title":"🔍 四大驗收層面","cards":[{"icon":"👁️","title":"視覺驗收","desc":"字體一致性、色彩正確性、間距對齊、響應式適配"},{"icon":"🖱️","title":"互動驗收","desc":"按鈕點擊、表單提交、頁面跳轉、動畫效果"},{"icon":"⚡","title":"功能驗收","desc":"資料儲存、流程完整、錯誤處理、邊界情況"},{"icon":"🔒","title":"安全驗收","desc":"權限控管、資料加密、輸入驗證、錯誤處理"}]}', 2);
INSERT INTO public.unit_sections (unit_id, type, content_json, sort_order) VALUES
('d0000000-0000-0000-0000-000000000010', 'text', '{"title":"UI 組件百科","body":"掌握常見的 UI 組件，了解何時該使用什麼組件，是設計良好使用者體驗的基礎。"}', 1),
('d0000000-0000-0000-0000-000000000010', 'card_grid', '{"title":"常用組件分類","cards":[{"icon":"📝","title":"表單組件","desc":"Input、Select、Checkbox、Radio、Switch、DatePicker","note":"收集使用者輸入"},{"icon":"📊","title":"資料展示","desc":"Table、Card、List、Badge、Avatar、Progress","note":"呈現結構化資料"},{"icon":"🔔","title":"反饋通知","desc":"Toast、Alert、Dialog、Modal、Tooltip","note":"與使用者互動溝通"},{"icon":"🧭","title":"導航組件","desc":"Navbar、Sidebar、Tabs、Breadcrumb、Pagination","note":"引導使用者瀏覽"}]}', 2);
